// Route model preference to correct model ID
const input = $input.all()[0].json;
const modelMap = {
  'sonnet': 'claude-sonnet-4-6',
  'opus': 'claude-opus-4-6',
  'haiku': 'claude-haiku-4-5-20251001'
};

const model = modelMap[input.model] || modelMap['sonnet'];
const maxTokens = input.model === 'opus' ? 8192 : 4096;

return [{
  json: {
    ...input,
    model_id: model,
    max_tokens: maxTokens,
    retry_count: 0,
    max_retries: 3
  }
}];

// Parse successful response and extract usage for cost logging
const response = $input.all()[0].json;
const body = response.body || response;

const content = body.content?.[0]?.text || '';
const inputTokens = body.usage?.input_tokens || 0;
const outputTokens = body.usage?.output_tokens || 0;

// Cost calculation (as of 2025)
const costs = {
  'claude-sonnet-4-6': { input: 3.00 / 1000000, output: 15.00 / 1000000 },
  'claude-opus-4-6': { input: 15.00 / 1000000, output: 75.00 / 1000000 },
  'claude-haiku-4-5-20251001': { input: 0.80 / 1000000, output: 4.00 / 1000000 }
};

const modelCost = costs[$json.model_id] || costs['claude-sonnet-4-6'];
const inputCost = inputTokens * modelCost.input;
const outputCost = outputTokens * modelCost.output;

// Try to parse JSON from response if it looks like JSON
let parsedContent = content;
try {
  const jsonMatch = content.match(/```json\n([\s\S]*?)\n```/) || content.match(/\{[\s\S]*\}/);
  if (jsonMatch) {
    parsedContent = JSON.parse(jsonMatch[1] || jsonMatch[0]);
  }
} catch (e) {
  // Keep as string if not valid JSON
}

return [{
  json: {
    content: content,
    parsed_content: parsedContent,
    model: $json.model_id,
    input_tokens: inputTokens,
    output_tokens: outputTokens,
    input_cost: inputCost.toFixed(6),
    output_cost: outputCost.toFixed(6),
    total_cost: (inputCost + outputCost).toFixed(6),
    workflow_name: $json.workflow_name,
    client_name: $json.client_name,
    purpose: $json.purpose,
    timestamp: new Date().toISOString()
  }
}];

// Retry logic with exponential backoff
const input = $input.all()[0].json;
const retryCount = (input.retry_count || 0) + 1;
const maxRetries = input.max_retries || 3;

if (retryCount > maxRetries) {
  throw new Error(`Claude API failed after ${maxRetries} retries. Last error: ${JSON.stringify(input)}`);
}

// Exponential backoff: 2s, 4s, 8s
const backoffMs = Math.pow(2, retryCount) * 1000;
await new Promise(resolve => setTimeout(resolve, backoffMs));

return [{
  json: {
    ...input,
    retry_count: retryCount
  }
}];
